// ─── ast-checker ────────────────────────────────────────────────────────────

describe('ast-checker', () => {
  it('detectLanguage returns js for .js/.ts/.mjs', () => {
    assert.equal(detectLanguage('.js'), 'js');
    assert.equal(detectLanguage('.ts'), 'js');
    assert.equal(detectLanguage('.mjs'), 'js');
  });
  it('detectLanguage returns python for .py', () => {
    assert.equal(detectLanguage('.py'), 'python');
  });
  it('detectLanguage returns unknown for unrecognized extensions', () => {
    assert.equal(detectLanguage('.rs'), 'unknown');
  });
  it('stripCommentsAndStrings removes JS comments', () => {
    const result = stripCommentsAndStrings('x = 1; // comment here', '.js');
    assert.ok(!result.includes('comment'));
  });
  it('stripCommentsAndStrings removes Python comments', () => {
    const result = stripCommentsAndStrings('x = 1  # comment here', '.py');
    assert.ok(!result.includes('comment'));
  });
  it('isInCommentOrString detects match in JS string', () => {
    const code = 'const x = "ev' + 'al(bad)";';
    const match = code.match(/ev[a]l/);
    assert.ok(isInCommentOrString(code, match.index, '.js'));
  });
  it('isInCommentOrString returns false for match in code', () => {
    const code = 'ev' + 'al(userInput);';
    const match = code.match(/ev[a]l/);
    assert.ok(!isInCommentOrString(code, match.index, '.js'));
  });
});

