// ─── prompt-budget ──────────────────────────────────────────────────────────

describe('prompt-budget', () => {
  it('estimateTokens returns reasonable estimate', () => {
    const tokens = estimateTokens('hello world');
    assert.ok(tokens > 0);
    assert.ok(tokens < 10);
  });
  it('trackInjection tracks usage', () => {
    resetBudget();
    const result = trackInjection('block-message', 'short msg', { maxVerificationTokens: 500 });
    assert.ok(typeof result.tokens === 'number');
    assert.ok(typeof result.overBudget === 'boolean');
  });
  it('getBudgetReport returns report object', () => {
    resetBudget();
    trackInjection('block-message', 'test', {});
    const report = getBudgetReport();
    assert.ok(report.totalTokens >= 0);
    assert.ok(report.sources);
  });
  it('condenseIfOverBudget trims long messages', () => {
    const longViolation = { ruleId: 'x', cycle: 1, message: 'A'.repeat(200) };
    const result = condenseIfOverBudget([longViolation], { maxVerificationTokens: 10 });
    assert.ok(result[0].message.length <= longViolation.message.length);
  });
});

// ─── self-correction ────────────────────────────────────────────────────────

describe('self-correction', () => {
  it('buildCorrectionHint returns string for violations', () => {
    const hint = buildCorrectionHint([
      { ruleId: 'no-eval', remediation: 'Use JSON.parse instead' }
    ]);
    assert.ok(hint);
    assert.ok(hint.includes('no-eval'));
  });
  it('buildCorrectionHint returns empty for no violations', () => {
    const hint = buildCorrectionHint([]);
    assert.ok(!hint);
  });
  it('trackCorrectionAttempt tracks attempts per file', () => {
    resetCorrectionState();
    const r1 = trackCorrectionAttempt('/test.js', [{ ruleId: 'x' }]);
    assert.equal(r1.attempts, 1);
    assert.ok(!r1.isEscalated);
    trackCorrectionAttempt('/test.js', [{ ruleId: 'x' }]);
    trackCorrectionAttempt('/test.js', [{ ruleId: 'x' }]);
    const r3 = trackCorrectionAttempt('/test.js', [{ ruleId: 'x' }]);
    assert.ok(r3.attempts >= 3);
  });
  it('escalateIfNeeded returns message after 3+ attempts', () => {
    resetCorrectionState();
    trackCorrectionAttempt('/esc.js', [{ ruleId: 'rule-a' }]);
    trackCorrectionAttempt('/esc.js', [{ ruleId: 'rule-a' }]);
    trackCorrectionAttempt('/esc.js', [{ ruleId: 'rule-a' }]);
    const msg = escalateIfNeeded('/esc.js');
    assert.ok(msg);
    assert.ok(msg.includes('rule-a'));
  });
});

